bad = '()/:;<>{}'   # the truly breaking ones; quotes in subgraph titles are fine
issues = 0
for bi, b in enumerate(blocks, 1):
    for ln, line in enumerate(b.splitlines(), 1):
        s = line.strip()
        if s.startswith('subgraph'):  # quoted titles valid
            continue
        for m in re.finditer(r'\[+\(?([^\[\]\(\)]*?)\)?\]+', line):
            for ch in bad:
                if ch in m.group(1):
                    print(f"  NODE block {bi} L{ln} '{ch}': {s}"); issues+=1
        for m in re.finditer(r'\|"?([^|]*?)"?\|', line):
            for ch in bad:
                if ch in m.group(1):
                    print(f"  EDGE block {bi} L{ln} '{ch}': {s}"); issues+=1
print("REAL BREAKING-CHAR ISSUES:", issues)
print("Total blocks:", len(blocks))
